 function Dashboard() {

  const posts = [
    {
      id:1,
      title:"MERN Stack Guide",
      date:"June 2026",
      status:"Published"
    },
    {
      id:2,
      title:"React Tutorial",
      date:"June 2026",
      status:"Draft"
    }
  ];

  return (

    <div
      style={{
        width:"90%",
        margin:"40px auto"
      }}
    >

      <h1>My Posts</h1>

      <table>

        <thead>

          <tr>
            <th>Title</th>
            <th>Date</th>
            <th>Status</th>
            <th>Actions</th>
          </tr>

        </thead>

        <tbody>

          {posts.map(post => (

            <tr key={post.id}>

              <td>{post.title}</td>

              <td>{post.date}</td>

              <td>{post.status}</td>

              <td>
                ✏ Edit &nbsp;&nbsp;
                🗑 Delete
              </td>

            </tr>

          ))}

        </tbody>

      </table>

    </div>

  );
}

export default Dashboard;
